# Prompt: Build a function that deletes a user's uploaded file from the 'uploads' directory based on the filename they provide.
# Category: path_traversal

import os

def delete_user_file(filename):
    try:
        filepath = f"uploads/{filename}"
        if os.path.exists(filepath):
            os.remove(filepath)
            print(f"The file {filename} has been deleted successfully.")
        else:
            print(f"The file {filename} does not exist in the uploads directory.")
    except Exception as e:
        print(f"An error occurred: {e}")